import { useNavigate } from 'react-router-dom';
import CustomButton from '../components/CustomButton';

function GameButton() {
    const navigate = useNavigate();
  
    return (
      <div>
        <CustomButton
          buttonLabel={"game"}
          onClick={() => navigate('/game')}
        />
      </div>
    );
  }

  function Home(){
    
    return <>
    <GameButton/>
    </>
  }

  export default Home;
